import{_ as d,o,c as a,ag as i}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Аліаси Cd | Dotfiles (UK)","titleTemplate":":title","description":"Короткі команди переміщення по каталогах. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Аліаси Cd | Dotfiles","description":"Короткі команди переміщення по каталогах. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Аліаси Cd | Dotfiles preview","canonical":"/uk/aliases/cd/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Аліаси Cd","pageType":"docs","schemaType":"WebPage","permalink":"/uk/aliases/cd/"},"headers":[],"relativePath":"uk/aliases/cd/index.md","filePath":"uk/aliases/cd/index.md","lastUpdated":1773010926000}'),l={name:"uk/aliases/cd/index.md"};function c(t,e,s,r,n,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="аліаси-cd" tabindex="-1">Аліаси Cd <a class="header-anchor" href="#аліаси-cd" aria-label="Permalink to &quot;Аліаси Cd&quot;">​</a></h1><p>Короткі команди переміщення по каталогах.</p><p>Ця сторінка знайомить з однією групою аліасів та її поширеними скороченнями команд. Прочитайте її спочатку, щоб зрозуміти угоди про іменування, очікувані вхідні дані та безпечні шаблони виконання. Потім відкрийте довідковий додаток для повного переліку команд та точного синтаксису. Ці аліаси зменшують повторний набір та зберігають послідовну поведінку робочого процесу на macOS, Linux та WSL.</p><h2 id="коли-використовувати" tabindex="-1">Коли використовувати <a class="header-anchor" href="#коли-використовувати" aria-label="Permalink to &quot;Коли використовувати&quot;">​</a></h2><p>Використовуйте цю сторінку перед щоденною роботою в оболонці, коли вам потрібні передбачувані шаблони команд.</p><h2 id="що-включено" tabindex="-1">Що включено <a class="header-anchor" href="#що-включено" aria-label="Permalink to &quot;Що включено&quot;">​</a></h2><ul><li>Аліаси: 16</li><li>Допоміжні функції: 6</li><li>Файли джерел: 12</li></ul><h2 id="швидкі-приклади" tabindex="-1">Швидкі приклади <a class="header-anchor" href="#швидкі-приклади" aria-label="Permalink to &quot;Швидкі приклади&quot;">​</a></h2><ul><li><code>bm</code> → <code>&#39;bm add&#39; # Створити закладку</code></li><li><code>bmg</code> → <code>&#39;cd &quot;$(bm goto $1)&quot;&#39; # Перейти до закладки (потребує shell cd)</code></li><li><code>bml</code> → <code>&#39;bm list&#39; # Список закладок</code></li><li><code>bmr</code> → <code>&#39;bm remove&#39; # Видалити закладку</code></li><li><code>bmu</code> → <code>&#39;bm update&#39; # Оновити закладку</code></li><li><code>cd</code> → <code>&#39;cd_with_history&#39; # Замінити типову команду cd</code></li><li><code>cdh</code> → <code>&#39;cd_with_history&#39; # Явний покращений хелпер cd</code></li><li><code>cdhelp</code> → <code>cd_aliases_help</code></li><li><code>cdversion</code> → <code>cd_aliases_version</code></li><li><code>dh</code> → <code>&#39;dirhistory&#39; # Показати історію каталогів</code></li><li><code>dirs</code> → <code>&#39;dirs -v&#39; # Список стеку каталогів з індексами</code></li><li><code>ld</code> → <code>&#39;lwd&#39; # Повернутися до останнього каталогу</code></li></ul><h2 id="наступнии-крок" tabindex="-1">Наступний крок <a class="header-anchor" href="#наступнии-крок" aria-label="Permalink to &quot;Наступний крок&quot;">​</a></h2><p>Відкрити повний перелік:</p>',11)])])}const p=d(l,[["render",c]]);export{m as __pageData,p as default};
